@dataclass
class Demo:
    title: str
    scenes: list[Scene]
    width: int = 1920
    height: int = 1080

@dataclass
class Action:
    type: ActionType
    params: dict
    trigger_word: str | None = None

class TTSBackend(ABC):
    @abstractmethod
    def synth(self, text: str) -> AudioClip: ...

class SilentTTSBackend(TTSBackend):   # zero deps
class SystemTTSBackend(TTSBackend):   # macOS say / espeak
class KokoroTTSBackend(TTSBackend):   # neural, optional
